solution.css:
*, *::before, *::after { margin: 0; padding: 0; box-sizing: border-box; }
body { font-family: system-ui, sans-serif; overflow: hidden; }

.categories {
  display: flex;
  overflow-x: auto;
  overflow-y: hidden;
  width: 100vw;
  height: 100vh;
  scroll-snap-type: x mandatory;
  scroll-behavior: smooth;
}

.category {
  flex: 0 0 100vw;
  height: 100vh;
  scroll-snap-align: start;
  scroll-snap-stop: always;
  position: relative;
}

.products {
  height: 100vh;
  overflow-y: auto;
  scroll-snap-type: y proximity;
}

.product {
  height: 100vh;
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: 2rem;
  font-weight: 700;
  color: white;
  scroll-snap-align: start;
}

